INSERT INTO public.entries (entry_type, subject, teacher, date, summary, attachment_url) VALUES ('DiaryEntry', 'General', 'KAVITA SHEKHAR KALE', '2026-06-06', 'Basketball dso selection trial *SELECTION TRIAL SCHEDULE FOR BASKETBALL * Dear parents, Next week onwards we are taking selection trial for basketball game during PE period.Those who have interested for above-mentioned said selection trial please present on PE period .Basketball students kindly bring it their own basketball for selection trial . Basketball students have to wear their PE uniform . One student will select only one game for dso competition , No one will allowed to take a part in two team game. *PFA Age criteria for DSO competition 2026-2027* 1) Under 14 age category for girls & boys VI standard onwards - 1 January 2013 birth or after birth 2)Under 17 age category for girls & boys VI std to XII std in between- 1 January 2010 birth or after birth Regards, Mrs kavita Shekhar Kale Basketball coach .', NULL);
INSERT INTO public.entries (entry_type, subject, teacher, date, summary, attachment_url) VALUES ('DiaryEntry', 'General', 'MONU NISHAD', '2026-06-06', 'Football U-17 Final trails list Hello Students, According to the selection list, the shortlisted students will participate in the final trial. The Grade 9 and Grade 10 teams will be combined into one squad for the final trial. The team selected through this trial will represent the school in both the DSO and Subroto tournaments. Please note that there will be only one final trial, and the selected team will participate in both competitions. There will be no separate trials for DSO and Subroto. Best of luck to all the shortlisted players!', 'https://cdn-mcb.myclassboard.com/gcscorp17schools/2/0/Diary/62026/0606261933180139.jpg');
